def validIPAddress(queryIP):
    if '.' in queryIP:
        pts = queryIP.split('.')
        if len(pts) != 4: return 'Neither'
        for p in pts:
            if not p.isdigit() or not 0 <= int(p) <= 255 or (len(p) > 1 and p[0] == '0'): return 'Neither'
        return 'IPv4'
    elif ':' in queryIP:
        pts = queryIP.split(':')
        if len(pts) != 8: return 'Neither'
        for p in pts:
            if not 1 <= len(p) <= 4 or not all(c.isdigit() or c.lower() in 'abcdef' for c in p): return 'Neither'
        return 'IPv6'
    return 'Neither'

